// app/create/page.tsx
'use client';

import { useState, useEffect } from 'react';
import { useRouter } from 'next/navigation';
import ProgressBar from '@/components/wizard/ProgressBar';
import Step1BasicInfo from '@/components/wizard/Step1BasicInfo';
import Step2Childhood from '@/components/wizard/Step2Childhood';
import Step3Career from '@/components/wizard/Step3Career';
import Step4Relationships from '@/components/wizard/Step4Relationships';
import { MemorialData, BasicInfo, ChildhoodInfo, CareerEducation, RelationshipsFamily, TOTAL_STEPS } from '@/types/memorial';

// Initial state for memorial data
const getInitialData = (): MemorialData => ({
    step1: {
        fullName: '',
        birthDate: '',
        deathDate: null,
        isStillLiving: false,
        birthPlace: '',
        deathPlace: '',
        profilePhoto: null,
        profilePhotoPreview: null,
        epitaph: '',
    },
    step2: {
        childhoodHome: '',
        familyBackground: '',
        schools: {
            elementary: '',
            highSchool: '',
            college: '',
            additionalEducation: '',
        },
        childhoodPersonality: [],
        earlyInterests: [],
        childhoodPhotos: [],
    },
    step3: {
        occupations: [],
        careerHighlights: [],
        education: {
            major: '',
            graduationYear: '',
            honors: '',
        },
    },
    step4: {
        partners: [],
        children: [],
        majorLifeEvents: [],
    },
    step5: {
        personalityTraits: [],
        coreValues: [],
        passions: [],
        lifePhilosophy: '',
        favoriteQuotes: [],
        memorableSayings: [],
    },
    step6: {
        biography: '',
        lifeChapters: [],
    },
    step7: {
        sharedMemories: [],
        impactStories: [],
        invitedEmails: [],
    },
    step8: {
        coverPhoto: null,
        coverPhotoPreview: null,
        gallery: [],
        videos: [],
        voiceRecordings: [],
        legacyStatement: '',
    },
    currentStep: 1,
    lastSaved: null,
});

export default function CreateMemorialPage() {
    const router = useRouter();
    const [memorialData, setMemorialData] = useState<MemorialData>(getInitialData());
    const [isSaving, setIsSaving] = useState(false);
    const [savedIndicator, setSavedIndicator] = useState(false);

    // Load from localStorage on mount
    useEffect(() => {
        const saved = localStorage.getItem('memorial_draft');
        if (saved) {
            try {
                const parsed = JSON.parse(saved);
                setMemorialData(parsed);
            } catch (error) {
                console.error('Failed to load draft:', error);
            }
        }
    }, []);

    // Auto-save to localStorage
    useEffect(() => {
        const saveToLocalStorage = () => {
            setIsSaving(true);
            localStorage.setItem('memorial_draft', JSON.stringify(memorialData));
            setTimeout(() => {
                setIsSaving(false);
                setSavedIndicator(true);
                setTimeout(() => setSavedIndicator(false), 2000);
            }, 300);
        };

        // Debounce auto-save
        const timer = setTimeout(saveToLocalStorage, 1000);
        return () => clearTimeout(timer);
    }, [memorialData]);

    const updateStep1 = (data: BasicInfo) => {
        setMemorialData(prev => ({
            ...prev,
            step1: data,
            lastSaved: new Date().toISOString(),
        }));
    };

    const updateStep2 = (data: ChildhoodInfo) => {
        setMemorialData(prev => ({
            ...prev,
            step2: data,
            lastSaved: new Date().toISOString(),
        }));
    };

    const updateStep3 = (data: CareerEducation) => {
        setMemorialData(prev => ({
            ...prev,
            step3: data,
            lastSaved: new Date().toISOString(),
        }));
    };

    const updateStep4 = (data: RelationshipsFamily) => {
        setMemorialData(prev => ({
            ...prev,
            step4: data,
            lastSaved: new Date().toISOString(),
        }));
    };

    const goToNextStep = () => {
        if (memorialData.currentStep < TOTAL_STEPS) {
            setMemorialData(prev => ({
                ...prev,
                currentStep: prev.currentStep + 1,
            }));
            window.scrollTo({ top: 0, behavior: 'smooth' });
        }
    };

    const goToPreviousStep = () => {
        if (memorialData.currentStep > 1) {
            setMemorialData(prev => ({
                ...prev,
                currentStep: prev.currentStep - 1,
            }));
            window.scrollTo({ top: 0, behavior: 'smooth' });
        }
    };

    const saveDraftAndExit = () => {
        localStorage.setItem('memorial_draft', JSON.stringify(memorialData));
        router.push('/');
    };

    return (
        <div className="min-h-screen bg-ivory">
            {/* Progress Bar */}
            <ProgressBar currentStep={memorialData.currentStep} />

            {/* Auto-save indicator */}
            <div className="fixed top-20 right-6 z-40">
                {isSaving && (
                    <div className="bg-charcoal/90 text-ivory px-4 py-2 rounded-full text-xs flex items-center gap-2">
                        <div className="w-2 h-2 bg-ivory rounded-full animate-pulse" />
                        Saving...
                    </div>
                )}
                {savedIndicator && (
                    <div className="bg-sage text-ivory px-4 py-2 rounded-full text-xs flex items-center gap-2">
                        <span>✓</span>
                        Saved
                    </div>
                )}
            </div>

            {/* Step Content */}
            <div className="pb-20">
                {memorialData.currentStep === 1 && (
                    <Step1BasicInfo
                        data={memorialData.step1}
                        onUpdate={updateStep1}
                        onNext={goToNextStep}
                    />
                )}

                {/* TODO: Add other steps here as we build them */}
                {memorialData.currentStep === 2 && (
                    <Step2Childhood
                        data={memorialData.step2}
                        onUpdate={updateStep2}
                        onNext={goToNextStep}
                        onBack={goToPreviousStep}
                    />
                )}

                {memorialData.currentStep === 3 && (
                    <Step3Career
                        data={memorialData.step3}
                        onUpdate={updateStep3}
                        onNext={goToNextStep}
                        onBack={goToPreviousStep}
                    />
                )}

                {memorialData.currentStep === 4 && (
                    <Step4Relationships
                        data={memorialData.step4}
                        onUpdate={updateStep4}
                        onNext={goToNextStep}
                        onBack={goToPreviousStep}
                    />
                )}

                {memorialData.currentStep >= 5 && (
                    <div className="max-w-3xl mx-auto px-6 py-12">
                        <h2 className="font-serif text-4xl text-charcoal mb-3">
                            Step {memorialData.currentStep}
                        </h2>
                        <p className="text-charcoal/60 mb-8">Steps 5-9 coming soon...</p>
                        <div className="flex gap-4">
                            <button
                                onClick={goToPreviousStep}
                                className="px-6 py-3 border border-sand/40 rounded-xl hover:bg-sand/10 transition-all"
                            >
                                ← Back
                            </button>
                        </div>
                    </div>
                )}
            </div>
        </div>
    );
}